import type { Page } from '@playwright/test';

export interface E2EMember { id: string; email: string; password: string; }

const TEST_MEMBERS: Record<string, E2EMember> = {
  alice: { id: 'm_alice', email: 'alice@e2e.test', password: 'pw-alice' },
  bob:   { id: 'm_bob',   email: 'bob@e2e.test',   password: 'pw-bob' },
};

export async function signInAs(page: Page, who: keyof typeof TEST_MEMBERS): Promise<E2EMember> {
  const m = TEST_MEMBERS[who];
  await page.goto('/login');
  await page.fill('[data-test=login-email]', m.email);
  await page.fill('[data-test=login-password]', m.password);
  await page.click('[data-test=login-submit]');
  await page.waitForSelector('[data-test=app-shell]');
  return m;
}

export async function openChannel(page: Page, channelId: string) {
  await page.click(`[data-test=channel-link-${channelId}]`);
  await page.waitForSelector('[data-test=channel-pane]');
}

export async function sendMessage(page: Page, body: string) {
  await page.fill('[data-test=composer-input]', body);
  await page.click('[data-test=composer-send]');
}

export async function setDNDViaAPI(page: Page, memberId: string, manualOn: boolean) {
  // Hit the implementer's DND endpoint via fetch from the browser context.
  await page.evaluate(async ({ memberId, manualOn }) => {
    await fetch(`/api/members/${memberId}/dnd`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ manual_on: manualOn }),
    });
  }, { memberId, manualOn });
}
